settings.custom_liquid:
{% comment %}
BLOQUE: Guía de tallas dinámica para productos.

Este código:
- Obtiene el estilo del producto desde el metafield product.metafields.custom.style
- Según el estilo asigna una imagen de guía de tallas
- Solo muestra el botón si existe una guía de tallas
- La guía aparece con animación usando CSS y JavaScript
{% endcomment %}

<style>
.size-guide-container {
  max-width: 800px;
  margin: 0 auto;
  text-align: center;
}

.size-guide-button {
  background-color: #4D4D4D;
  color: white;
  border: none;
  padding: 10px 20px;
  font-size: 14px;
  cursor: pointer;
  border-radius: 5px;
  transition: background-color 0.3s;
}

.size-guide-button:hover {
  background-color: #333;
}

.size-guide-content {
  max-height: 0;
  overflow: hidden;
  transition: max-height 0.5s ease-in-out, opacity 0.5s ease-in-out;
  opacity: 0;
  margin-top: 15px;
}

.size-guide-content.active {
  max-height: 500px;
  opacity: 1;
}
</style>

{% assign estilo = product.metafields.custom.style %}
{% assign imagen_url = '' %}

{% if estilo %}
  {% case estilo %}
    {% when 'patron-camiseta-regular-1' %}
      {% assign imagen_url = 'https://cdn.shopify.com/s/files/1/0891/7205/0264/files/patron-camiseta-regular-1.jpg?v=1772640328' %}

    {% when 'patron-sudadera-cropped' %}
      {% assign imagen_url = 'https://cdn.shopify.com/s/files/1/0891/7205/0264/files/patron-sudadera-cropped.jpg?v=1742042149' %}

    {% when 'patron-regular-hoodie-1' %}
      {% assign imagen_url = 'https://cdn.shopify.com/s/files/1/0891/7205/0264/files/patron-regular-hoodie-1.jpg?v=1772698596' %}

    {% when 'patron-camiseta-regular-2' %}
      {% assign imagen_url = 'https://cdn.shopify.com/s/files/1/0891/7205/0264/files/patron-camiseta-regular-2.jpg?v=1742042373' %}

    {% when 'patron-camiseta-oversize' %}
      {% assign imagen_url = 'https://cdn.shopify.com/s/files/1/0891/7205/0264/files/patron-camiseta-oversize.jpg?v=1742042148' %}

    {% when 'patron-regular-hoodie-2' %}
      {% assign imagen_url = 'https://cdn.shopify.com/s/files/1/0891/7205/0264/files/patron-regular-hoodie-2.jpg?v=1772698613' %}

    {% when 'patron-camiseta-cuello-scoop-oversize' %}
      {% assign imagen_url = 'https://cdn.shopify.com/s/files/1/0891/7205/0264/files/patron-camiseta-cuello-scoop-oversize.jpg?v=1742042149' %}

    {% when 'patron-camiseta-croptop-1' %}
      {% assign imagen_url = 'https://cdn.shopify.com/s/files/1/0891/7205/0264/files/patron-camiseta-croptop-1.png' %}

    {% when 'patron-camiseta-croptop-2' %}
      {% assign imagen_url = 'https://cdn.shopify.com/s/files/1/0891/7205/0264/files/patron-camiseta-croptop-2.png' %}

    {% when 'pantalon-carpenter' %}
      {% assign imagen_url = 'https://cdn.shopify.com/s/files/1/0891/7205/0264/files/pantalon-carpenter.png?v=1772700875' %}
  {% endcase %}
{% endif %}

{% if imagen_url != '' %}
  <div class="size-guide-container">
    <button
      class="size-guide-button"
      type="button"
      data-show="{{ 'size_guide.show' | t }}"
      data-hide="{{ 'size_guide.hide' | t }}"
      onclick="toggleSizeGuide(this)"
    >
      {{ 'size_guide.show' | t }}
    </button>

    <div class="size-guide-content">
      <img src="{{ imagen_url }}" alt="Guía de Tallas - {{ estilo }}" style="max-width: 100%; height: auto;">
    </div>
  </div>
{% endif %}

<script>
function toggleSizeGuide(button) {
  var container = button.closest(".size-guide-container");
  var content = container.querySelector(".size-guide-content");

  var showText = button.dataset.show;
  var hideText = button.dataset.hide;

  if (content.classList.contains("active")) {
    content.classList.remove("active");
    button.textContent = showText;
  } else {
    content.classList.add("active");
    button.textContent = hideText;
  }
}
</script>
